def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0.0
        additive = 0.0
        decay = 1.0
        multiplier = 1.0
        for j in range(1, 15):
            if j % 5 == 0:
                decay *= 0.85
                multiplier += 0.1
            if ratio < (0.04 * j):
                base = (j ** 2) * ((1 - ratio) ** 3) * decay * multiplier
                if cap % (j+2) == 0:
                    base += np.log1p(j*j)
                else:
                    base -= np.sqrt(j*j + cap)
                score += base
            else:
                modify = j * np.exp(-ratio * j * 0.85) * decay / (j+2)
                if (cap*j + j*j) % 4 == 0:
                    modify += np.cos(ratio * j**1.1)
                else:
                    modify -= np.sin(ratio * j**1.2)
                score += modify
            if j % 3 == 0:
                additive += np.tanh(score / (j + 1)) * np.sin(j * ratio)
            elif j % 2 == 0:
                additive -= np.arctan(score / (j + 1)) * np.cos(j * ratio)
            else:
                additive += np.sinh(score / (j + 1)) * np.tanh(ratio * j)
        for k in range(1, 7):
            residual = cap - item * k
            if residual > 0:
                if residual % (k+1) == 0:
                    score += np.log1p(residual ** 1.1) / (k + 0.7)
                else:
                    score -= (residual ** 0.3) / (k + 1.7) * np.tanh(residual / (k+2))
            else:
                penalty = abs(residual) ** 1.5 * 0.12 * k
                if penalty > 5:
                    penalty = 5 + np.log1p(penalty - 5)
                score -= penalty
        scaling = np.log1p(cap * ratio + 1) + np.sqrt(item) + 0.5
        final_value = (score + additive) / (cap + 1)
        if final_value > 0:
            priorities[i] = -final_value * np.exp(-ratio) * np.cos(ratio * np.pi)
        elif final_value < -0.5:
            priorities[i] = -final_value * scaling * np.sin(ratio * np.pi / 2)
        else:
            priorities[i] = -final_value * (np.log1p(cap + 1) + np.sqrt(item + 1))
    return priorities
